from collections import deque
from unittest.mock import patch

from django.http import HttpResponse
from django.middleware.ratelimit import RateLimitMiddleware
from django.test import RequestFactory, SimpleTestCase
from django.test.utils import override_settings


def get_response(request):
    return HttpResponse("OK")


def make_middleware(**kwargs):
    """Return a fresh RateLimitMiddleware instance with a clean tracking state."""
    RateLimitMiddleware._requests.clear()
    RateLimitMiddleware._request_count = 0
    with override_settings(**kwargs):
        return RateLimitMiddleware(get_response)


class RateLimitMiddlewareSettingsTests(SimpleTestCase):
    def test_default_settings(self):
        mw = make_middleware()
        self.assertEqual(mw.limit, 100)
        self.assertEqual(mw.window, 3600)

    @override_settings(RATE_LIMIT_REQUESTS=50, RATE_LIMIT_WINDOW=60)
    def test_custom_settings(self):
        RateLimitMiddleware._requests.clear()
        RateLimitMiddleware._request_count = 0
        mw = RateLimitMiddleware(get_response)
        self.assertEqual(mw.limit, 50)
        self.assertEqual(mw.window, 60)


class RateLimitMiddlewareRequestTests(SimpleTestCase):
    factory = RequestFactory()

    def setUp(self):
        RateLimitMiddleware._requests.clear()
        RateLimitMiddleware._request_count = 0

    def _make_request(self, ip="1.2.3.4"):
        return self.factory.get("/", REMOTE_ADDR=ip)

    @override_settings(RATE_LIMIT_REQUESTS=3, RATE_LIMIT_WINDOW=60)
    def test_requests_within_limit_are_allowed(self):
        mw = RateLimitMiddleware(get_response)
        for _ in range(3):
            response = mw.process_request(self._make_request())
            self.assertIsNone(response)

    @override_settings(RATE_LIMIT_REQUESTS=3, RATE_LIMIT_WINDOW=60)
    def test_request_exceeding_limit_returns_403(self):
        mw = RateLimitMiddleware(get_response)
        for _ in range(3):
            mw.process_request(self._make_request())
        response = mw.process_request(self._make_request())
        self.assertIsNotNone(response)
        self.assertEqual(response.status_code, 403)

    @override_settings(RATE_LIMIT_REQUESTS=3, RATE_LIMIT_WINDOW=60)
    def test_different_ips_tracked_independently(self):
        mw = RateLimitMiddleware(get_response)
        for _ in range(3):
            mw.process_request(self._make_request(ip="10.0.0.1"))

        # 10.0.0.1 is at the limit; 10.0.0.2 should still be allowed.
        self.assertEqual(
            mw.process_request(self._make_request(ip="10.0.0.1")).status_code, 403
        )
        self.assertIsNone(mw.process_request(self._make_request(ip="10.0.0.2")))

    @override_settings(RATE_LIMIT_REQUESTS=2, RATE_LIMIT_WINDOW=60)
    def test_requests_outside_window_are_not_counted(self):
        mw = RateLimitMiddleware(get_response)
        past = 0.0  # epoch — well outside any 60-second window

        with patch("django.middleware.ratelimit.time.time", return_value=past):
            mw.process_request(self._make_request())
            mw.process_request(self._make_request())

        # Both old timestamps are now expired; a new request should be allowed.
        with patch("django.middleware.ratelimit.time.time", return_value=past + 120):
            response = mw.process_request(self._make_request())
        self.assertIsNone(response)

    @override_settings(RATE_LIMIT_REQUESTS=1, RATE_LIMIT_WINDOW=60)
    def test_full_middleware_call_returns_403(self):
        """Verify the 403 propagates through the full __call__ path."""
        mw = RateLimitMiddleware(get_response)
        mw(self._make_request())  # consume the single allowed slot
        response = mw(self._make_request())
        self.assertEqual(response.status_code, 403)

    @override_settings(RATE_LIMIT_REQUESTS=5, RATE_LIMIT_WINDOW=60)
    def test_full_middleware_call_passes_through_when_allowed(self):
        mw = RateLimitMiddleware(get_response)
        response = mw(self._make_request())
        self.assertEqual(response.status_code, 200)


class RateLimitMiddlewareCleanupTests(SimpleTestCase):
    factory = RequestFactory()

    def setUp(self):
        RateLimitMiddleware._requests.clear()
        RateLimitMiddleware._request_count = 0

    def _make_request(self, ip="1.2.3.4"):
        return self.factory.get("/", REMOTE_ADDR=ip)

    @override_settings(RATE_LIMIT_REQUESTS=200, RATE_LIMIT_WINDOW=60)
    def test_cleanup_removes_expired_ips_every_100_requests(self):
        mw = RateLimitMiddleware(get_response)
        past = 0.0

        # Record one request for a distinct IP far in the past.
        with patch("django.middleware.ratelimit.time.time", return_value=past):
            mw.process_request(self._make_request(ip="9.9.9.9"))

        self.assertIn("9.9.9.9", RateLimitMiddleware._requests)

        # Advance time beyond the window and send 99 more requests to trigger
        # the cleanup that fires on the 100th request.
        future = past + 120
        with patch("django.middleware.ratelimit.time.time", return_value=future):
            for i in range(99):
                mw.process_request(self._make_request(ip=f"192.168.1.{i % 254 + 1}"))

        # The 100th request triggers _cleanup; 9.9.9.9's entry should be gone.
        with patch("django.middleware.ratelimit.time.time", return_value=future):
            mw.process_request(self._make_request(ip="192.168.2.1"))

        self.assertNotIn("9.9.9.9", RateLimitMiddleware._requests)

    @override_settings(RATE_LIMIT_REQUESTS=200, RATE_LIMIT_WINDOW=60)
    def test_cleanup_retains_active_ips(self):
        mw = RateLimitMiddleware(get_response)
        now = 1_000_000.0

        with patch("django.middleware.ratelimit.time.time", return_value=now):
            mw.process_request(self._make_request(ip="5.5.5.5"))

        # Send 99 more requests to reach the cleanup threshold.
        with patch("django.middleware.ratelimit.time.time", return_value=now):
            for i in range(99):
                mw.process_request(self._make_request(ip=f"10.0.{i // 254}.{i % 254 + 1}"))

        # Trigger cleanup — 5.5.5.5 is still within the window and must survive.
        with patch("django.middleware.ratelimit.time.time", return_value=now):
            mw.process_request(self._make_request(ip="10.1.0.1"))

        self.assertIn("5.5.5.5", RateLimitMiddleware._requests)

    @override_settings(RATE_LIMIT_REQUESTS=200, RATE_LIMIT_WINDOW=60)
    def test_request_count_increments_on_every_call(self):
        mw = RateLimitMiddleware(get_response)
        initial = RateLimitMiddleware._request_count
        for _ in range(5):
            mw.process_request(self._make_request())
        self.assertEqual(RateLimitMiddleware._request_count, initial + 5)

